<script setup>
import ArticleHeader from '@/components/ArticleHeader.vue'
import ArticleBody from '@/components/ArticleBody.vue'

const post = {
  id: "springboot-actuator",
  title: "Spring Boot Actuator와 모니터링",
  date: "2026-02-11",
  summary: "Actuator 엔드포인트, 헬스체크, 메트릭, 커스텀 엔드포인트, 보안 설정까지 운영 환경에 필요한 모니터링 요소를 정리합니다.",
  category: "Technology/SpringBoot",
  tags: ["springboot","actuator","monitoring","health","metrics"],
  content: ["## Spring Boot Actuator란?", "Actuator는 애플리케이션의 헬스, 메트릭, 환경 정보 등을 HTTP 또는 JMX로 노출하는 Spring Boot 모듈입니다. 쿠버네티스 liveness/readiness 프로브, Prometheus, Grafana와 연동할 때 필수입니다.", "", "## 1) 실습: IntelliJ 프로젝트 셋업", "이론에 앞서, 직접 프로젝트를 만들어 Actuator를 체험해 봅시다.", "", "### 1-1) 프로젝트 생성 (IntelliJ IDEA)", "1. **File → New → Project** 선택", "2. **Spring Initializr** 탭에서 아래와 같이 설정:", "   - **Name**: `springboot_actuator_example`", "   - **Language**: Java", "   - **Type**: Gradle - Groovy", "   - **JDK**: 21", "3. **Dependencies** 추가:", "   - **Developer Tools → Lombok**", "   - **Web → Spring Web**", "   - **Ops → Spring Boot Actuator**", "4. **Create** 클릭", "", "### 1-2) build.gradle", "```groovy", "plugins {", "    id 'java'", "    id 'org.springframework.boot' version '3.4.3'", "    id 'io.spring.dependency-management' version '1.1.7'", "}", "", "group = 'com.example'", "version = '0.0.1-SNAPSHOT'", "", "java {", "    toolchain {", "        languageVersion = JavaLanguageVersion.of(21)", "    }", "}", "", "configurations {", "    compileOnly {", "        extendsFrom annotationProcessor", "    }", "}", "", "repositories {", "    mavenCentral()", "}", "", "dependencies {", "    implementation 'org.springframework.boot:spring-boot-starter-web'", "    implementation 'org.springframework.boot:spring-boot-starter-actuator'", "    compileOnly 'org.projectlombok:lombok'", "    annotationProcessor 'org.projectlombok:lombok'", "    testImplementation 'org.springframework.boot:spring-boot-starter-test'", "}", "", "tasks.named('test') {", "    useJUnitPlatform()", "}", "```", "", "### 1-3) 소스 코드", "", "**DemoApplication.java**", "```java", "package com.example.springboot_actuator_example;", "", "import org.springframework.boot.SpringApplication;", "import org.springframework.boot.autoconfigure.SpringBootApplication;", "", "@SpringBootApplication", "public class DemoApplication {", "    public static void main(String[] args) {", "        SpringApplication.run(DemoApplication.class, args);", "    }", "}", "```", "", "**CustomHealthIndicator.java** — `AbstractHealthIndicator`를 상속하여 커스텀 서비스 상태를 체크합니다.", "```java", "package com.example.springboot_actuator_example;", "", "import org.springframework.boot.actuate.health.AbstractHealthIndicator;", "import org.springframework.boot.actuate.health.Health;", "import org.springframework.stereotype.Component;", "", "@Component", "public class CustomHealthIndicator extends AbstractHealthIndicator {", "", "    @Override", "    protected void doHealthCheck(Health.Builder builder) throws Exception {", "        boolean serviceUp = checkCustomService();", "        if (serviceUp) {", "            builder.up()", "                .withDetail(\"customService\", \"Available\")", "                .withDetail(\"version\", \"1.0.0\");", "        } else {", "            builder.down()", "                .withDetail(\"customService\", \"Unavailable\")", "                .withDetail(\"error\", \"Service not responding\");", "        }", "    }", "", "    private boolean checkCustomService() {", "        return true;", "    }", "}", "```", "", "**CustomInfoContributor.java** — `InfoContributor`를 구현하여 빌드·팀 정보를 추가합니다.", "```java", "package com.example.springboot_actuator_example;", "", "import org.springframework.boot.actuate.info.Info;", "import org.springframework.boot.actuate.info.InfoContributor;", "import org.springframework.stereotype.Component;", "", "import java.util.Map;", "", "@Component", "public class CustomInfoContributor implements InfoContributor {", "", "    @Override", "    public void contribute(Info.Builder builder) {", "        builder.withDetail(\"build\", Map.of(", "            \"artifact\", \"springboot_actuator_example\",", "            \"version\", \"1.0.0\",", "            \"description\", \"Spring Boot Actuator 실습 프로젝트\"", "        ));", "        builder.withDetail(\"team\", Map.of(", "            \"name\", \"Backend Team\",", "            \"contact\", \"backend@example.com\"", "        ));", "    }", "}", "```", "", "**HelloController.java**", "```java", "package com.example.springboot_actuator_example;", "", "import org.springframework.web.bind.annotation.GetMapping;", "import org.springframework.web.bind.annotation.RestController;", "", "@RestController", "public class HelloController {", "", "    @GetMapping(\"/api/hello\")", "    public String hello() {", "        return \"Hello, Actuator!\";", "    }", "}", "```", "", "### 1-4) application.yml", "```yaml", "server:", "  port: 8080", "", "management:", "  endpoints:", "    web:", "      exposure:", "        include: \"*\"", "  endpoint:", "    health:", "      show-details: always", "  info:", "    env:", "      enabled: true", "", "info:", "  app:", "    name: springboot_actuator_example", "    description: Spring Boot Actuator 실습", "    version: 1.0.0", "```", "", "### 1-5) Postman으로 테스트", "애플리케이션을 실행(`Run`)한 뒤 아래 엔드포인트를 Postman(또는 브라우저)에서 호출합니다.", "", "| 요청 | URL | 설명 |", "|------|-----|------|", "| GET | `http://localhost:8080/actuator` | 사용 가능한 모든 Actuator 엔드포인트 목록 |", "| GET | `http://localhost:8080/actuator/health` | 커스텀 헬스 포함 상태 확인 |", "| GET | `http://localhost:8080/actuator/info` | 빌드/팀 정보 (CustomInfoContributor) |", "| GET | `http://localhost:8080/actuator/metrics` | JVM, HTTP 등 메트릭 목록 |", "| GET | `http://localhost:8080/actuator/env` | 환경 변수 및 설정값 |", "", "`/actuator/health` 응답 예시:", "```json", "{", "  \"status\": \"UP\",", "  \"components\": {", "    \"custom\": {", "      \"status\": \"UP\",", "      \"details\": {", "        \"customService\": \"Available\",", "        \"version\": \"1.0.0\"", "      }", "    },", "    \"diskSpace\": { \"status\": \"UP\" },", "    \"ping\": { \"status\": \"UP\" }", "  }", "}", "```", "", "## 2) 기본 엔드포인트", "| 엔드포인트 | 설명 |", "|------------|------|", "| /actuator/health | 애플리케이션 및 DB, 디스크 등 상태 |", "| /actuator/info | 빌드 정보 등 (직접 설정) |", "| /actuator/metrics | JVM, HTTP, DB 등 메트릭 |", "| /actuator/env | 환경 변수, 설정값 |", "| /actuator/loggers | 로거 레벨 조회/변경 |", "", "## 3) Health 상세화", "```java", "@Component", "public class CustomHealthIndicator implements HealthIndicator {", "    private final RestTemplate restTemplate;", "", "    @Override", "    public Health health() {", "        try {", "            restTemplate.getForObject(\"https://external-api.com/status\", String.class);", "            return Health.up().withDetail(\"external-api\", \"OK\").build();", "        } catch (Exception e) {", "            return Health.down().withDetail(\"error\", e.getMessage()).build();", "        }", "    }", "}", "```", "", "## 4) Prometheus 메트릭 노출 (선택)", "```xml", "<dependency>", "    <groupId>io.micrometer</groupId>", "    <artifactId>micrometer-registry-prometheus</artifactId>", "</dependency>", "```", "", "```yaml", "management:", "  endpoints:", "    web:", "      exposure:", "        include: health, info, prometheus", "```", "", "`/actuator/prometheus`에서 Prometheus 형식 메트릭을 scrape할 수 있습니다.", "", "## 5) 커스텀 메트릭", "```java", "@Service", "public class OrderService {", "    private final Counter orderCounter;", "    private final Timer orderTimer;", "", "    public OrderService(MeterRegistry registry) {", "        orderCounter = registry.counter(\"orders.created\", \"status\", \"success\");", "        orderTimer = registry.timer(\"orders.process.time\");", "    }", "", "    public void createOrder(Order order) {", "        orderTimer.record(() -> {", "            // 주문 처리 로직", "            orderCounter.increment();", "        });", "    }", "}", "```", "", "## 6) 쿠버네티스 Liveness/Readiness", "```yaml", "livenessProbe:", "  httpGet:", "    path: /actuator/health/liveness", "    port: 8080", "readinessProbe:", "  httpGet:", "    path: /actuator/health/readiness", "    port: 8080", "```", "", "Spring Boot 2.3+에서는 `management.health.livenessstate`와 `readinessstate`를 사용해 k8s 프로브에 맞게 분리할 수 있습니다.", "", "## 7) 보안", "Actuator 엔드포인트는 민감 정보를 다룰 수 있으므로, Spring Security로 보호하고 IP 제한 또는 기본 인증을 적용하는 것이 좋습니다.", "", "## 정리", "Actuator는 운영 모니터링의 핵심 도구입니다. health + metrics만으로도 기본 운영이 가능하고, Prometheus/Grafana와 조합하면 강력한 관측성이 확보됩니다."]
}
</script>

